require('dotenv').config();
const { ethers } = require('ethers');

// --- Configuration ---
const PRIVATE_KEY = process.env.PRIVATE_KEY;
const INFURA_PROJECT_ID = process.env.INFURA_PROJECT_ID; // Or ALCHEMY_API_KEY
const NETWORK = 'sepolia'; // e.g., 'mainnet', 'sepolia', 'goerli', etc.

if (!PRIVATE_KEY) {
    console.error('Error: PRIVATE_KEY environment variable not set. Please set it in your .env file.');
    process.exit(1);
}
if (!INFURA_PROJECT_ID) {
    console.error('Error: INFURA_PROJECT_ID environment variable not set. Please set it in your .env file.');
    process.exit(1);
}

// --- Initialize Provider and Wallet ---
// We use InfuraProvider here. You can easily switch to AlchemyProvider or JsonRpcProvider.
const provider = new ethers.InfuraProvider(NETWORK, INFURA_PROJECT_ID);

// Create a wallet instance from the private key and connect it to the provider.
// This wallet will be used to sign all transactions.
const wallet = new ethers.Wallet(PRIVATE_KEY, provider);

console.log(`Wallet address: ${wallet.address}`);
console.log(`Connected to network: ${NETWORK}`);

// --- Core Functions ---

/**
 * Sends a specified amount of ETH from the configured wallet to a target address.
 *
 * @param {string} toAddress The recipient's Ethereum address.
 * @param {string} amountEth The amount of ETH to send (e.g., "0.01").
 * @returns {Promise<ethers.providers.TransactionReceipt>} The transaction receipt object.
 */
async function sendEth(toAddress, amountEth) {
    try {
        console.log(`Sending ${amountEth} ETH to ${toAddress}...`);

        const value = ethers.parseEther(amountEth); // Convert ETH string to Wei BigInt

        const transaction = {
            to: toAddress,
            value: value,
        };

        // Estimate gas limit for the transaction
        const gasLimit = await wallet.estimateGas(transaction);
        console.log(`Estimated gas limit: ${gasLimit.toString()}`);

        // Send the transaction with the estimated gas limit
        const txResponse = await wallet.sendTransaction({
            ...transaction,
            gasLimit: gasLimit,
        });

        console.log(`Transaction sent! Hash: ${txResponse.hash}`);
        console.log(`Waiting for transaction to be mined...`);

        // Wait for the transaction to be mined and get the receipt
        const receipt = await txResponse.wait();
        console.log(`Transaction mined in block: ${receipt.blockNumber}`);
        console.log(`Gas used: ${receipt.gasUsed.toString()}`);
        console.log(`ETH transfer successful!`);
        return receipt;
    } catch (error) {
        console.error('Error sending ETH:', error.message);
        throw error;
    }
}

/**
 * Interacts with a smart contract by sending a transaction (e.g., calling a write function).
 *
 * @param {string} contractAddress The address of the smart contract.
 * @param {ethers.ContractInterface} abi The ABI of the smart contract.
 * @param {string} methodName The name of the contract method to call.
 * @param {Array<any>} args An array of arguments for the contract method.
 * @param {string} [valueEth="0"] Optional amount of ETH to send with the transaction (e.g., for payable functions).
 * @returns {Promise<ethers.providers.TransactionReceipt>} The transaction receipt.
 */
async function interactWithContract(contractAddress, abi, methodName, args = [], valueEth = '0') {
    try {
        console.log(`Interacting with contract ${contractAddress}, method: ${methodName}(${args.join(', ')})`);

        // Create a contract instance connected to our signer (wallet)
        const contract = new ethers.Contract(contractAddress, abi, wallet);

        const value = ethers.parseEther(valueEth);

        // Prepare transaction options, including value if sending ETH
        const txOptions = { value: value };

        // Estimate gas for the contract call
        const estimatedGas = await contract[methodName].estimateGas(...args, txOptions);
        console.log(`Estimated gas for contract call: ${estimatedGas.toString()}`);

        // Call the contract method, sending the transaction
        const txResponse = await contract[methodName](...args, {
            ...txOptions,
            gasLimit: estimatedGas, // Set gas limit based on estimation
        });

        console.log(`Contract transaction sent! Hash: ${txResponse.hash}`);
        console.log(`Waiting for transaction to be mined...`);

        // Wait for the transaction to be mined and get the receipt
        const receipt = await txResponse.wait();
        console.log(`Contract transaction mined in block: ${receipt.blockNumber}`);
        console.log(`Gas used: ${receipt.gasUsed.toString()}`);
        console.log(`Contract interaction successful!`);
        return receipt;
    } catch (error) {
        console.error('Error interacting with contract:', error.message);
        throw error;
    }
}

/**
 * Reads data from a smart contract (calling a view/pure function).
 * This function does not send a transaction or modify blockchain state.
 *
 * @param {string} contractAddress The address of the smart contract.
 * @param {ethers.ContractInterface} abi The ABI of the smart contract.
 * @param {string} methodName The name of the contract method to call.
 * @param {Array<any>} args An array of arguments for the contract method.
 * @returns {Promise<any>} The result of the contract call.
 */
async function readContractData(contractAddress, abi, methodName, args = []) {
    try {
        console.log(`Reading from contract ${contractAddress}, method: ${methodName}(${args.join(', ')})`);

        // Create a contract instance connected to the provider for read-only calls
        const contract = new ethers.Contract(contractAddress, abi, provider);

        const result = await contract[methodName](...args);

        console.log(`Contract read successful. Result: ${result}`);
        return result;
    } catch (error) {
        console.error('Error reading contract data:', error.message);
        throw error;
    }
}

